mapper.select:
SELECT address_id, user_id, alias, zipcode, address, address_detail,
       is_default, status_code, created_at, updated_at, deleted_yn, deleted_at
FROM   USER_ADDRESSES
WHERE  address_id = #{addressId}
  AND  user_id    = #{userId}
  AND  deleted_yn = 'N'

mapper.update:
UPDATE USER_ADDRESSES
SET    alias = #{alias}
WHERE  address_id = #{addressId}
  AND  user_id    = #{userId}
  AND  deleted_yn = 'N'

UPDATE USER_ADDRESSES
SET    is_default = 'Y'
WHERE  address_id = #{addressId}
  AND  user_id    = #{userId}
  AND  deleted_yn = 'N'
